const body = $json.body || $json;
const id = String(body.id || ('promo-ai-' + Date.now())).trim();
const md = body.md || {};
const promo = body.promo || {};
const design = body.design || {};
const output = body.output || {};
const model = String(body.model || 'gpt-4o-mini').trim();
const n8nWebhookUrl = String(body.n8nWebhookUrl || body.n8n_webhook_url || '').trim();
const promptUrl = String(body.promptUrl || body.prompt_url || '').trim();

const requiredPromo = ['title', 'template', 'market', 'leadText', 'ctaLabel', 'ctaUrl', 'subline', 'termsText'];
const missingPromo = requiredPromo.filter((key) => !String(promo[key] || '').trim());
if (missingPromo.length) throw new Error('Missing promo fields: ' + missingPromo.join(', '));
if (!md.brand) throw new Error('md.brand is required');
if (!md.designConcept && !md.designPromptContext) throw new Error('md.designConcept or md.designPromptContext is required');

return [{
  json: {
    id,
    model,
    n8nWebhookUrl,
    promptUrl,
    md,
    promo,
    design,
    sourceDesign: body.sourceDesign || {},
    styleSource: body.styleSource || '',
    styleSourceLabel: body.styleSourceLabel || '',
    companyPreset: body.companyPreset || null,
    hasOverride: Boolean(body.hasOverride),
    output: {
      format: output.format || 'desktop_web_page',
      viewport: output.viewport || { width: 1440, minWidth: 1180 }
    }
  }
}];

const input = $('Normalize Payload').item.json;
const loadedPrompt = $json;
const concept = input.md.designConcept || {};
const conceptJson = concept.json || {};
const promptContext = input.md.designPromptContext || concept.promptContext || '';
const summary = input.md.summary || {};

const promptTemplate = String(
  loadedPrompt.prompt ||
  loadedPrompt.body?.prompt ||
  loadedPrompt.data?.prompt ||
  ''
).trim();

if (!promptTemplate) {
  throw new Error('External page generation prompt is empty');
}

const values = {
  brand: input.md.brand || '',
  slug: input.md.slug || '',
  designConceptSummary: concept.summary || conceptJson.brandConcept || '',
  designPromptContext: promptContext,
  designConceptJson: JSON.stringify(conceptJson, null, 2),
  categories: JSON.stringify(summary.categories || []),
  colors: JSON.stringify(summary.colors || []),
  fonts: JSON.stringify(summary.fonts || []),
  promoJson: JSON.stringify(input.promo, null, 2),
  designJson: JSON.stringify(input.design, null, 2),
  styleSource: input.styleSource || '',
  styleSourceLabel: input.styleSourceLabel || '',
  companyPreset: input.companyPreset || '',
  hasOverride: String(input.hasOverride)
};

const render = (template, data) => template.replace(/\{\{\s*([a-zA-Z0-9_]+)\s*\}\}/g, (match, key) => (
  Object.prototype.hasOwnProperty.call(data, key) ? String(data[key]) : match
));

const system = 'You are a senior brand-faithful promotional web designer and frontend engineer. Return valid JSON only. You must treat the selected MD as a binding design specification, not inspiration.';
const user = render(promptTemplate, values);

return [{
  json: {
    ...input,
    promptMeta: {
      id: loadedPrompt.id || loadedPrompt.body?.id || 'external-promo-page-generation',
      version: loadedPrompt.version || loadedPrompt.body?.version || '',
      url: input.promptUrl || ''
    },
    llmRequest: {
      model: input.model,
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user }
      ],
      temperature: 0.38,
      response_format: { type: 'json_object' }
    }
  }
}];

const input = $('Build Page Generation Prompt').item.json;
const response = $json;
const content = response.choices?.[0]?.message?.content || response.message?.content || response.content || response.text || response.output_text || '';
if (!content) throw new Error('LLM response content is empty');

let generated;
try {
  const fence = String.fromCharCode(96, 96, 96);
  generated = typeof content === 'string'
    ? JSON.parse(content.replace(new RegExp('^' + fence + 'json\\s*', 'i'), '').replace(new RegExp(fence + '$', 'i'), '').trim())
    : content;
} catch (error) {
  throw new Error('Failed to parse LLM JSON: ' + error.message);
}

if (!generated.html || !generated.css) throw new Error('LLM JSON must include html and css');
if (!generated.mdComplianceMap || typeof generated.mdComplianceMap !== 'object') {
  throw new Error('LLM JSON must include mdComplianceMap to prove MD requirements were applied');
}

const requiredCompliance = [
  'layoutPhilosophy',
  'visualMood',
  'componentStyle',
  'depthAndEffects',
  'shapeAndRadius',
  'promoPageImplications',
  'notColorFontOnlyProof'
];
const missingCompliance = requiredCompliance.filter((key) => !String(generated.mdComplianceMap[key] || '').trim());
if (missingCompliance.length) {
  throw new Error('mdComplianceMap missing fields: ' + missingCompliance.join(', '));
}

const proof = String(generated.mdComplianceMap.notColorFontOnlyProof || '').trim();
if (proof.length < 40) {
  throw new Error('mdComplianceMap.notColorFontOnlyProof is too weak');
}

const stripDangerous = (value) => String(value || '')
  .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '')
  .replace(/\son[a-z]+\s*=\s*(['"]).*?\1/gi, '')
  .replace(/javascript:/gi, '');

const htmlBody = stripDangerous(generated.html);
const css = stripDangerous(generated.css);
if (!/promo-generated-page/.test(htmlBody)) throw new Error('HTML must include .promo-generated-page root');

const title = String(input.promo.title || 'Promo Page').replace(/[<>]/g, '');
const fullHtml = "<!doctype html><html lang='ko'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>" + title + "</title><style>" + css + "</style></head><body>" + htmlBody + "</body></html>";

const staticData = $getWorkflowStaticData('global');
staticData.pages = staticData.pages || {};
staticData.pages[input.id] = {
  html: fullHtml,
  payload: input,
  designIntent: generated.designIntent || '',
  layoutSummary: generated.layoutSummary || '',
  mdComplianceMap: generated.mdComplianceMap,
  qualityChecks: generated.qualityChecks || [],
  createdAt: new Date().toISOString()
};

const queryPath = 'promo-ai-page-view?id=' + encodeURIComponent(input.id);
const sourceUrl = String(input.n8nWebhookUrl || '').trim();
let pageUrl = '/webhook/' + queryPath;

if (sourceUrl) {
  pageUrl = sourceUrl.replace(/promo-ai-page-generate(?:\?.*)?$/, queryPath);
} else {
  const headers = $('Generate AI Promo Page').item.json.headers || {};
  const proto = headers['x-forwarded-proto'] || 'https';
  const host = headers['x-forwarded-host'] || headers.host || '';
  if (host) pageUrl = proto + '://' + host + '/webhook/' + queryPath;
}

return [{
  json: {
    ok: true,
    id: input.id,
    pageUrl,
    designIntent: generated.designIntent || '',
    layoutSummary: generated.layoutSummary || '',
    mdComplianceMap: generated.mdComplianceMap,
    qualityChecks: generated.qualityChecks || [],
    payload: input
  }
}];

const id = $json.params?.id || $json.query?.id || '';
const staticData = $getWorkflowStaticData('global');
const page = staticData.pages?.[id];
const html = page?.html || `<!doctype html><html lang='ko'><head><meta charset='utf-8'><title>Promo page not found</title></head><body style='font-family:Arial,sans-serif;padding:40px'><h1>Promo page not found</h1><p>No generated page was stored for id: ${id}</p></body></html>`;
return [{ json: { html } }];
